//-------------------------------------------------------------------------
scwin.f_sndClsTotal = function () {
  var v_send = 0; //전송 
  var v_unSend = 0; //미전송
  var v_acpt = 0; //접수 
  var v_error = 0; //오류 
  var v_transComplete = 0; //전송완료
  var v_forceAcpt = 0; //강제접수

  for (var i = 0; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
    if (ds_cntrOutDeclarInfo.getCellData(i, "sndClsNm") == "전송") v_send++;else if (ds_cntrOutDeclarInfo.getCellData(i, "sndClsNm") == "미전송") v_unSend++;else if (ds_cntrOutDeclarInfo.getCellData(i, "sndClsNm") == "접수") v_acpt++;else if (ds_cntrOutDeclarInfo.getCellData(i, "sndClsNm") == "오류") v_error++;else if (ds_cntrOutDeclarInfo.getCellData(i, "sndClsNm") == "전송완료") v_transComplete++;else if (ds_cntrOutDeclarInfo.getCellData(i, "sndClsNm") == "강제접수") v_forceAcpt++;
  }
  send.setValue(v_send);
  unSend.setValue(v_unSend);
  acpt.setValue(v_acpt);
  error.setValue(v_error);
  transComplete.setValue(v_transComplete);
  forceAcpt.setValue(v_forceAcpt);
};

