scwin.gr_cntrOutDeclarInfo_oncelldblclick = async function (rowIndex, columnIndex, columnId) {
  let colid = columnId;
  if (colid == "crryinoutDeclarNo") {
    if (ds_cntrOutDeclarInfo.getCellData(rowIndex, "sndClsNm") == "오류") {
      scwin.f_errorPopUp(rowIndex);
    }
  }
  if (colid == "chk") {
    // 미반영된 반출 승인이 있는데 전송 하시겠습니까?  
    if (ds_cntrOutDeclarInfo.getCellData(rowIndex, "crryinoutBasisNoPre") != "") {
      if (!(await $c.win.confirm($p, "미반영된 반출 승인이 있습니다. 계속 진행 하시겠습니까?"))) {
        ds_cntrOutDeclarInfo.setCellData(rowIndex, "chk", 0);
        return false;
      }
    }
    if (ds_cntrOutDeclarInfo.getCellData(rowIndex, "sndClsCd") != "3" && ds_cntrOutDeclarInfo.getCellData(rowIndex, "sndClsNm") != "오류" && ds_cntrOutDeclarInfo.getCellData(rowIndex, "sndClsNm") != "전송완료" && ds_cntrOutDeclarInfo.getCellData(rowIndex, "sndClsNm") != "" && ds_cntrOutDeclarInfo.getCellData(rowIndex, "sndClsCd") != "4" && ds_cntrOutDeclarInfo.getCellData(rowIndex, "sndClsCd") != "5") {
      $c.gus.cfAlertMsg($p, "전송구분이 전송완료/미전송/전송제외/오류/필수항목오류인 경우에만 선택하실수 있습니다.");
      ds_cntrOutDeclarInfo.setCellData(rowIndex, "chk", 0);
      return false;
    }

    //같은 컨테이너번호 행 연동 체크
    for (var i = 0; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
      if (ds_cntrOutDeclarInfo.getCellData(rowIndex, "chk") == 1 && ds_cntrOutDeclarInfo.getCellData(rowIndex, "cntrNo") == ds_cntrOutDeclarInfo.getCellData(i, "cntrNo")) {
        ds_cntrOutDeclarInfo.setCellData(i, "chk", 1);
      }
    }
  }
};

